PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?saltMine ?saltMineLabel WHERE {
  ?saltMine wdt:P31 wd:Q40551 .
  ?saltMine wdt:P17 wd:Q30 .
  OPTIONAL {
    ?saltMine rdfs:label ?saltMineLabel .
    FILTER(LANG(?saltMineLabel) = "en")
  }
}
